/* High 32 bits of an unsigned 32x32 product. The freqlut lookup below needs
   it to stay 32-bit (no __aeabi_lmul). msfa_op.h reuses this one too. */
static inline uint32_t msfa_umulhi32(uint32_t a, uint32_t b) {
  uint32_t ah = a >> 16, al = a & 0xFFFF, bh = b >> 16, bl = b & 0xFFFF;
  uint32_t lo = al * bl;
  uint32_t m1 = ah * bl + (lo >> 16);
  uint32_t m2 = al * bh + (m1 & 0xFFFF);
  return ah * bh + (m1 >> 16) + (m2 >> 16);
}

/* Faithful Sin::lookup (sin.cc, SIN_DELTA). phase Q24/cycle. dy*lowbits is
   ~31-bit (|dy|<=102943, lowbits<2^14) so one signed 32-bit product suffices. */
static inline int32_t msfa_sin_lookup(int32_t phase) {
  const int SHIFT = 24 - MSFA_SIN_LG_N;
  int lowbits = phase & ((1 << SHIFT) - 1);
  int phase_int = (phase >> (SHIFT - 1)) & ((MSFA_SIN_N - 1) << 1);
  int32_t dy = msfa_sintab[phase_int];
  int32_t y0 = msfa_sintab[phase_int + 1];
  return y0 + ((dy * lowbits) >> SHIFT);
}

/* Faithful Freqlut::lookup (freqlut.cc). logfreq Q24, 1.0=octave. The table is
   monotonic so (y1-y0)>=0; the >>SAMPLE_SHIFT of a ~33-bit product is taken
   from its two 32-bit halves (msfa_umulhi32), staying 32-bit. */
static inline int32_t msfa_freqlut_lookup(int32_t logfreq) {
  const int SAMPLE_SHIFT = 24 - MSFA_SIN_LG_N;
  int ix = (logfreq & 0xffffff) >> SAMPLE_SHIFT;
  int32_t y0 = msfa_freqlut[ix];
  int32_t y1 = msfa_freqlut[ix + 1];
  uint32_t d = (uint32_t)(y1 - y0);
  uint32_t lowbits = (uint32_t)(logfreq & ((1 << SAMPLE_SHIFT) - 1));
  uint32_t prod_lo = d * lowbits;
  uint32_t prod_hi = msfa_umulhi32(d, lowbits);
  int32_t y = y0 + (int32_t)((prod_hi << (32 - SAMPLE_SHIFT)) | (prod_lo >> SAMPLE_SHIFT));
  int hibits = logfreq >> 24;
  return y >> (MSFA_MAX_LOGFREQ_INT - hibits);
}

